HOTEL_INFO["https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG_17010837052113.jpg"]={images:["https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG_17010837052113.jpg","https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG2_17010837052113.jpg","https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG3_17010837062113.jpg","https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG4_17010837062113.jpg","https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG5_17010837062113.jpg","https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG6_17010837072113.jpg","https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG7_17010837072113.jpg","https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG8_17010837072113.jpg","https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG9_17010837082113.jpg","https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG10_17010837082113.jpg","https://static.peakview.bg/img/data2/94/hoteli/2113/BIG_IMG11_17010837092113.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>RAMIRA BEACH HOTEL( EX.SUN MARITIM HOTEL)</strong></p><p>Ramira Beach Hotel - All Inclusive е с изглед към плажа и предлага 4-звездни помещения за настаняване в Авсалар. Разполага със сезонен открит плувен басейн, фитнес център и градина. На разположение на гостите има детски клуб, ресторант, воден парк и тераса. На разположение на гостите има денонощна рецепция, летищни трансфери, туристическо бюро и безплатен WiFi на цялата територия.</p><p>Климатизираните стаи в хотела разполагат с гардероб, електрическа кана, минибар, сейф, телевизор с плосък екран, балкон и самостоятелна баня с душ.</p><p>Всяка сутрин в Ramira Beach Hotel - All Inclusive се сервира континентална закуска.</p><p>На разположение на гостите има детска площадка. В Ramira Beach Hotel - All Inclusive можете да играете билярд, тенис на маса и дартс, както и да наемете автомобил.</p><p>Общественият плаж Avsallar е на 500 метра от хотела, а плажът Incekum е на 1,9 километра. Най-близкото летище е Газипаша-Алания, на 64 км от Ramira Beach Hotel - All Inclusive. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG_17308248533305.jpg"]={images:["https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG_17308248533305.jpg","https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG2_17308248543305.jpg","https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG3_17308248553305.jpg","https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG4_17308248563305.jpg","https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG5_17308248573305.jpg","https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG6_17308248583305.jpg","https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG7_17308248593305.jpg","https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG8_17308248593305.jpg","https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG9_17308248613305.jpg","https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG10_17308248623305.jpg","https://static.peakview.bg/img/data2/94/hoteli/3305/BIG_IMG11_17308248633305.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>MYSEA HOTEL INCEKUM</strong></p><p> WEBSITE на хотела</p><p>Разположение: Хотелът се намира на 90 км от летището в Анталия, на 75 км от летището в Алания, на 20 км от Алания, в село Турклер, на 70 м от собствения плаж през пътя. Построен през 1999 г., обща площ 3 800 м2. Последният ремонт се състоя през 2017 г.</p><p>На територията на хотела: Основен ресторант, 2 бара, открит басейн, закрит басейн, 2 водни пързалки, СПА център, магазини, пералня, лекар на повикване.</p><p>Безплатни услуги: сауна, турска баня, фитнес, анимация, дартс, тенис на маса, водна гимнастика, аеробика.</p><p>Платени услуги: масажи и други процедури, билярд, водни моторизирани спортове, WI-FI.</p><p>За децата: мини клуб (4-12г.), детски басейн, детска площадка.</p><p>В стаите: Хотелът се състои от една 5-етажна сграда и разполага с общо 130 стаи. Стаите са оборудвани с индивидуален климатик, телевизор със сателитен приемник, телефон, баня с душ, сешоар, минибар (вода - безплатно), сейф (срещу заплащане), балкон, под - ламинат. Почистване на стаите - ежедневно, смяна на спално бельо - веднъж седмично.</p><p>Изхранване: All Inclusive - закуска, обяд и вечеря на блок маса в основния ресторант и консумация на местни алкохолни и безалкохолни напитки.</p><p>Плаж: Собствен пясъчен плаж на 70 м от хотела през пътя. Чадъри, шезлонги на плажа и при басейна безплатно. Плажни кърпи срещу депозит.</p><p>* Забележка: Администрацията на хотела си запазва правото да прави промени в изпълнението на концепцията си спрямо сезона, без предварително предупреждение.</p><p>FACTSHEETS</p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/94/hoteli/3306/BIG_IMG_17308248713306.jpg"]={images:["https://static.peakview.bg/img/data2/94/hoteli/3306/BIG_IMG_17308248713306.jpg","https://static.peakview.bg/img/data2/94/hoteli/3306/BIG_IMG2_17308248723306.jpg","https://static.peakview.bg/img/data2/94/hoteli/3306/BIG_IMG3_17308248733306.jpg","https://static.peakview.bg/img/data2/94/hoteli/3306/BIG_IMG4_17308248743306.jpg","https://static.peakview.bg/img/data2/94/hoteli/3306/BIG_IMG5_17308248753306.jpg","https://static.peakview.bg/img/data2/94/hoteli/3306/BIG_IMG6_17308248763306.jpg","https://static.peakview.bg/img/data2/94/hoteli/3306/BIG_IMG7_17308248783306.jpg","https://static.peakview.bg/img/data2/94/hoteli/3306/BIG_IMG8_17308248803306.jpg","https://static.peakview.bg/img/data2/94/hoteli/3306/BIG_IMG9_17308248813306.jpg","https://static.peakview.bg/img/data2/94/hoteli/3306/BIG_IMG10_17308248823306.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>MYSEA HOTELS ALARA</strong></p><p> WEBSITE на хотела</p><p>Разположение: Хотелът се намира в района на курортното селище Окурджалар, на 30 км от Алания, на около 90 км от международното летище в Анталия, на втора линия от плажа.</p><p>На територията: Основен бюфет ресторант, бар, външен басейн, вътрешен басейн, СПА център турска баня, сауна, фитнес зала, тенис на маса, билярд, плажен волейбол, обменно бюро, коли под наем, велосипеди под наем, Wifi срещу допълнително заплащане.</p><p>В стаите: климатик, телевизор, сателитна телевизия, сешоар, тоалетни принадлежности.</p><p>Концепцие на хранене: All Inclusive</p><p>Плаж: Собствен, пясъчно-чакълест, на разстояние около 300 м.</p><p>Забележка: Администрацията на хотела си запазва правото да прави промени в концепцията на хотела спрямо сезона,без предварително предупреждение.</p>"};
